const joi = require('joi');

// Generate random offsets to distribute cron execution across instances
// Random seconds (0-59) for more distribution granularity
const randomSeconds = Math.floor(Math.random() * 60);
// Random minute offset (0-4) to distribute execution every 5 minutes
const randomOffset = Math.floor(Math.random() * 5);

module.exports = {
  CRON_EVENT_TYPE: 'CRON_JOB',
  CRON_CSP_CONFIG_NAME: 'CSP_CONFIG',
  CRON_CSP_STORAGE_KEY: 'cspConfig',
  CRON_CSP_TIME: `${randomSeconds} ${randomOffset}/5 * * * *`, // every 5 minutes with random seconds and minute offset
  CRON_SECURITY_CONFIG_NAME: 'SECURITY_CONFIG',
  CRON_SECURITY_STORAGE_KEY: 'securityConfig',
  CRON_SECURITY_TIME: `${new Date().getMinutes()} */1 * * *`,
  CRON_CONFIG_SCHEMA: joi.object({
    name: joi.string().required().trim().empty(),
    cronTime: joi.string().required().trim().empty(),
    handler: joi.function().required(),
  }),
  CRON_WORKER_READY_TYPE: 'CRON_WORKER_READY',
};
